CREATE TABLE `article_analysis` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `article_id` bigint NOT NULL COMMENT '文章ID',
  `summary` text COLLATE utf8mb4_unicode_ci COMMENT '文章摘要',
  `keywords` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关键词(JSON数组)',
  `word_count` int NOT NULL DEFAULT '0' COMMENT '总字数',
  `reading_time_minutes` int NOT NULL DEFAULT '0' COMMENT '阅读时长(分钟)',
  `analyzed_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '分析时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_article_id` (`article_id`)
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='文章分析结果';
